var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"밀어붙여라! 밀어붙여! 흡혈귀 놈들을 죽여라!","JPN":"追い込め！　追い込めろ！　吸血鬼のやつらを殺せ！","ENG":"Charge! Attack! Kill those vampire scum!","TWN":"衝上去！衝上去！殺死那些吸血鬼！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"놈들의 영지는 이제 우리의 땅이 될 것이다!","JPN":"やつらの領地はこれで我々のものだ！","ENG":"Their land will soon be ours!","TWN":"他們的領地將成為我們的土地！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"으아악!","JPN":"あああ！","ENG":"Aaah!","TWN":"啊啊啊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"비켜! 뒤에 좀 비키라고!","JPN":"どけ！　後ろ、どけよ！","ENG":"Get out of the way! Let me through!","TWN":"讓開！往後退一點！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"부관! 병사들이 대체 왜 저러고 있지? 아까 전부터 전혀 앞으로 나아가지 못하고 있지 않나!","JPN":"副官！　兵士たちは何してるんだ？　さっきからまったく前へ進んでいないじゃないか！","ENG":"Hey! What are those soldiers doing?! Why aren’t they advancing forward?!","TWN":"副官！士兵們到底在幹什麼？從剛才開始怎麼就一動不動了啊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"공작님! 그게… 고위 흡혈귀로 보이는 자 하나가 영지의 입구를 막고 있습니다.","JPN":"公爵！　それが……高位の吸血鬼らしき者が領地の入口を塞いでいます。","ENG":"Sir! Well... There seems to be a high-class vampire blocking the entrance.","TWN":"報告公爵！有…有一個看起來像是高階吸血鬼的傢伙擋在了領地入口。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"고위 흡혈귀라고? 이제 몇 마리 남지도 않은 족속이 스스로 전선까지 기어 나왔단 말인가? 그것도 혼자?","JPN":"高位の吸血鬼だと？　もう何匹も残っていない輩が、自ら戦線まで出てきやがったのか？　それも1人で？","ENG":"A high-class vampire? Those things are almost extinct, but one has decided to come out of its hole? And alone at that?","TWN":"高階吸血鬼？已經所剩無幾的族群竟然自己爬到前線來了？而且還是一個人？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"흐흐, 오히려 잘 됐어. 보물이 제 발로 걸어 들어온 셈이군.","JPN":"ふふ、むしろチャンスだ。宝物が自分の足でやってきたものだな。","ENG":"Keke... Excellent! My luck just keeps getting better!","TWN":"呵呵，正合我意。寶物自己送上門來了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"당장 놈의 심장을 뽑아서 내게 가져오도록.","JPN":"今すぐにやつの心臓を抜き取って私に持って来い。","ENG":"Bring me his heart!","TWN":"立刻把那傢伙的心臟挖出來帶給我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"그것들을 풀어도 상관없다.","JPN":"あれを使っても構わん。","ENG":"I’ll allow using those savages.","TWN":"把那些傢伙放出來也無妨。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"…알겠습니다.","JPN":"……わかりました。","ENG":"...Yes, sir.","TWN":"…遵命。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"전원, 전열 재정비! 선두는 괴수를 풀어라!","JPN":"全員、戦列を再整備しろ！　先頭は怪獣を出せ！","ENG":"All, change front formation! Put the beasts in front!","TWN":"全體聽令，整頓隊伍！在前線釋放怪物！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"흐음, 처음엔 야만스럽게 떼로 덤비시더니… 이번엔 길들인 야수종인가요?","JPN":"ふーん、最初は野蛮に群がって攻撃してきましたが……今度は躾けた野獣種ですか？","ENG":"Hmm... First, you charge in like barbarians... Now, you send in your tamed beasts?","TWN":"哼，一開始是成群撲上來…這次是被馴服的野獸種嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"정말이지. 재미있게 해주시는 분들이군요.","JPN":"まったく。退屈しない方々ですね。","ENG":"You people never cease to surprise me.","TWN":"真是的，終於有點意思了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"이, 이럴 수가… 고작 권총 하나로 괴수 무리를 전부 처치하다니 대체 어떻게?","JPN":"そ、そんな……ピストル1丁で怪獣の群れを全部倒すとは、いったいどうやって？","ENG":"I-I don’t believe it...! He killed all those beasts with just a revolver... How’s that even possible?","TWN":"這，這怎麼可能？！竟然用一把手槍就解決了所有怪物！到底是怎麼做到的？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"별 말씀을. 그저 가볍게 피하면서 급소만 노렸을 뿐이랍니다.","JPN":"ふふ、朝飯前でしたよ。ただ軽くよけながら急所を狙ったまでですから。","ENG":"Why, thank you. All I did was avoid their attacks and shoot for their weak spots.","TWN":"小意思，我只是輕鬆地閃避了幾下，然後瞄準要害開了幾槍而已。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"네놈! 감히 날 비웃는 거냐!","JPN":"貴様！　私をからかっているのか！","ENG":"How dare you mock me!","TWN":"你這傢伙！竟敢嘲諷我！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"잠깐, 그러고 보니 네 옷의 그 문장은 설마…… 프레데릭 가문?","JPN":"待て、そういえば貴様の服のその紋章、まさか……フレドレック家？","ENG":"Wait.. That crest on his clothes... Could it be the Frederick family?","TWN":"等一下，仔細一看，你衣服上的那個徽章，難道是…弗雷德里克家族的？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>결투자 프레데릭</color>이란 피도 눈물도 없다는 흡혈귀가…… 바로 너였나?!","JPN":"<color=#ffd34c>決闘者フレドレック</color>という血も涙もない吸血鬼とは……貴様のことだったのか！？","ENG":"So you’re the heartless vampire, <color=#ffd34c>Frederick the Duelist</color>!","TWN":"<color=#ffd34c>決鬥者弗雷德里克</color>那個沒血沒淚的吸血鬼…就是你嗎？！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런, 제 하찮은 이름을 바우어 공작께서 알고 계시다니 영광일 따름이군요.","JPN":"おっと、私のくだらない名前をバウアー公爵がご存じだったとは、光栄ですね。","ENG":"Oh my, it’s an honor for a person of your status to recognize a low-life like me, Duke Bower.","TWN":"哎呀，能讓鮑爾公爵知道我這微不足道的名字，真是榮幸之至啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"하, 하지만 내 라이칸스로프는 혼자서 성벽을 찢어발기는 괴물이다!","JPN":"だ、だが私のライカンスロープは1人で城壁を切り裂く化け物だ！","ENG":"B-but my lycanthropes are monsters that can tear down castle walls singlehandedly!","TWN":"但，但我的狼人可是能撕裂城牆的怪物啊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"게다가 지금은 보름달이 뜬 밤이지!","JPN":"しかも今夜は満月の夜！","ENG":"Plus, there’s a full moon tonight!","TWN":"而且今晚是月圓之夜！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"네 놈이 제아무리 대단하다고 해도 이놈들 전부를 이기는 건 불가능해!","JPN":"貴様がいくら有能でも、こいつらを全部倒しきるのは不可能なのだ！","ENG":"Even if you are as strong as people say, you can’t possibly defeat all of them!","TWN":"就算你再厲害，也不可能打敗他們所有人！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"당신의 라이칸스로프라…….","JPN":"あなたのライカンスロープ、ですか……","ENG":"Your lycanthropes, eh?","TWN":"你的狼人…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"라이칸스로프는 본래 지극히 이성적인 사냥꾼들입니다.","JPN":"ライカンスロープは元々、とても理性的な狩人なのです。","ENG":"Lycanthropes are originally intelligent and rational hunters.","TWN":"狼人原本是極其理性的獵人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"조련이란 명목으로 그들의 지성을 망가뜨리고 그저 달려들 줄 밖에 모르는 괴물로 만든 건 당신들이죠. 안 그렇습니까?","JPN":"操練という名目で彼らの知性を壊し、ただ飛びかかることしか能のない化け物にしたのはあなたたちでしょう。違いますか？","ENG":"But you’re the one who turned them into mindless monsters who only know how to attack, no?","TWN":"以馴養之名摧毀他們的智慧，把他們變成只會撲上來的怪物，不是你們幹的嗎？不是嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"크윽… 뭣들 하나! 당장 저 놈을…!","JPN":"くうっ……何をしている！　今すぐやつを……！","ENG":"Krr... Men! Get that-!","TWN":"呃…你們在幹什麼！快把那傢伙…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"공작님!","JPN":"公爵！","ENG":"Sir!","TWN":"公爵！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"크아악! 내 손… 손이! 내 반지가…!","JPN":"ぐああ！　私の手……手が！　私の指輪が……！","ENG":"Aargh! My hand! My ring...!","TWN":"啊啊啊！手…我的手！我的戒指…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"네 노옴…! 내가 누구인 줄 알고…!","JPN":"貴様……！　私が誰だと……！","ENG":"You...! Do you not know who I am?!","TWN":"你這傢伙…！知道我是誰嗎…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"잘 알고 있습니다.","JPN":"ちゃんと知っています。","ENG":"Of course I do!","TWN":"我很清楚。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"전장에 나오면서 싸울 준비도 되어 있지 않은 이기적이고 연약한 인간이죠.","JPN":"戦場に出るというのに戦う準備もできていない、自分勝手で軟弱な人間。","ENG":"You’re a foolish and weak human being who shouldn’t be on the battlefield.","TWN":"是個上了戰場，卻沒有做好戰鬥準備的自私又脆弱的人類。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"…뭣이?","JPN":"……何だと！？","ENG":"...What?","TWN":"…什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저 프레데릭 도마. 비록 하찮은 흡혈귀일 뿐이나 난잡한 싸움 보다는 명예로운 일대일의 결투를 선호한답니다.","JPN":"私、フレドレック・ドマ。くだらない吸血鬼に過ぎませんが、乱雑な戦いよりは名誉のある一対一の決闘が好みです。","ENG":"I, Frederick\xA0Doma, may be a lowly vampire... But I prefer an honorable duel rather than this pathetic thing you call a battle.","TWN":"我，弗雷德里克·多馬。雖然只是個微不足道的吸血鬼，但我更喜歡光明正大的單挑，而不是混戰。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저와 결투를 원한다면 지금이라도 당장 그 허리춤의 총을 쥐어 보이십시오.","JPN":"私と決闘したいのなら、今すぐにでもその腰の銃を手に取ってください。","ENG":"If you want to duel me, why don’t you grab that pistol of yours on your side?","TWN":"如果你想和我決鬥，現在就拔出你腰間的槍。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"물론 그때가 되면, 손가락 하나로 봐 드리지는 않을 겁니다.","JPN":"もちろんその時は、指一本では済みません。","ENG":"But if you do... your finger will be the least of your worries.","TWN":"當然，到那時，我可不會手下留情。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"크으윽…!","JPN":"くううっ……！","ENG":"Gah...!","TWN":"呃啊…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"뭣들 하나! 돌아간다!","JPN":"何をしている！　帰るぞ！","ENG":"What are you waiting for?! Head back!!","TWN":"你們在幹什麼！快帶我回去！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"생각보다 탄약을 많이 낭비해버렸네요.","JPN":"予想以上に弾薬を無駄遣いしましたね。","ENG":"It seems that I have wasted too many bullets.","TWN":"比想像中浪費了更多彈藥呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"마왕의 군세도 점점 강해지고 있는 모양이군요. 인간의 군대가 일족의 땅까지 들어오다니.","JPN":"魔王の軍勢もますます強くなっているようです。人間の軍隊が一族の地まで入ってくるとは。","ENG":"The Demon Lord’s army must be growing stronger by the second. I can’t believe the human army is already at our doorsteps.","TWN":"看來魔王的軍隊也越來越強大了。人類的軍隊竟然能進入我們一族的領地。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이대로 가다간 정말로 살아갈 땅이 부족해질 수도 있겠어요.","JPN":"このままでは、生活可能な土地が段々足りなくなるかもしれません。","ENG":"At this rate, there won’t be any land left for my people.","TWN":"照這樣下去，真的可能會沒有足夠的土地可以生存。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"당신은… 아직 도망가지 않은 겁니까?","JPN":"あなたは……まだ逃げていなかったのですか？","ENG":"Aren’t you... gonna run away?","TWN":"你…你還沒逃跑嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"우, 웃기지 마라! 흉악한 흡혈귀 놈.","JPN":"ふ、ふざけるな！　邪悪な吸血鬼め。","ENG":"O-over my dead body! You wretched vampire freak!","TWN":"開什麼玩笑！你這個殘暴的吸血鬼。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"공작이 도망쳤으니, 내가 네 녀석의 심장을 가져가겠다.","JPN":"公爵が逃げたから、僕が貴様の心臓を持って帰る。","ENG":"The Duke’s hightailed it out of here, so it’s my turn to carve out your heart!","TWN":"既然公爵逃跑了，那讓我來取走你的心臟吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 유감이지만 저도 당신들처럼 심장은 하나라서요.","JPN":"ふふ、残念ですが私もあなたたちのように心臓は1つですので。","ENG":"Hah hah... I’m sorry, but I only have one heart, like you.","TWN":"呵呵，很遺憾，我也和你們一樣只有一顆心。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"나눠 드릴 수 있는 여분의 심장 같은 건 없답니다.","JPN":"分けてあげられる余分の心臓などありません。","ENG":"I need this one, and I don’t have a spare to give you.","TWN":"沒有多餘的心臟分給你喔。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"깔보지 마! 너처럼 영생을 누리는 흡혈귀에겐 인간이 우습겠지?!","JPN":"なめるな！　お前みたいに永生を生きる吸血鬼には、人間がさぞ滑稽に見えるんだろう！？","ENG":"Am I a joke to you?! I bet you immortal vampires think we humans are pathetic!","TWN":"別小看我！像你這種享受永生的吸血鬼，肯定覺得人類很可笑吧？！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"네 놈의 심장만 있으면… 난 어머니를 검은 역병으로부터 구할 수 있어.","JPN":"でも貴様の心臓があれば……僕はお母さんを黒い疫病から救い出せる。","ENG":"But if I have your heart... I could use it to save my mother from the Black Plague.","TWN":"只要有了你的心臟…我就能將母親從黑死病中救出。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"영생을 드릴 수도 있다고!","JPN":"永生をあげられるんだ！","ENG":"I can even give her eternal life!","TWN":"還可以讓她有永生！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"어머니를 위한 효심이라. 기특하군요.","JPN":"母への親孝行ですか。健気なものです。","ENG":"All for your mother... How sweet of you.","TWN":"原來是為了救母親啊，這孝心真是難得。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 이 심장을 먹는다고 해서 정말 영생을 얻을 수 있을까요?","JPN":"ですが、この心臓を食べるとして本当に永生を手に入れることができるのでしょうか？","ENG":"But do you really believe consuming my heart will give her eternal life?","TWN":"但是吃了這顆心臟，真的能獲得永生嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、何だと？","ENG":"W-what’s that supposed to mean?","TWN":"什，什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"적어도 분명한 건, 저 같은 잡종 흡혈귀의 심장으로 검은 역병을 치유할 수는 없답니다.","JPN":"少なくとも確かなのは、私のような雑種の心臓で黒い疫病を治療することはできないということです。","ENG":"What I know for certain is that a half-vampire’s heart like mine can’t cure the Black Plague.","TWN":"至少可以肯定的是，像我這樣的混血吸血鬼的心臟是無法治癒黑死病的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그것만은 제가 장담해드리죠.","JPN":"それだけは保証しましょう。","ENG":"That, I can assure you it’s true.","TWN":"這一點我可以保證。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"큭…! 거짓말하지 마!","JPN":"くっ……！　ウソつけ！","ENG":"Krr...! Don't lie to me!","TWN":"唔…！你說謊！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"동국의 왕은 그 심장 하나에 나라를 걸었다고 했어!","JPN":"東国の王はその心臓一つに国をかけたって聞いた！","ENG":"The king of the eastern kingdom is rewarding an entire country for that heart!","TWN":"東國的王曾說要將國家的命運賭在那顆心臟上！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"그만한 값어치가 없다면 대체 왜 그런 짓을 했겠어?","JPN":"価値がないなら、そんなことをするはずないだろう？","ENG":"Why would he do that if it wasn’t true?!","TWN":"如果不是真的，為什麼要那樣做呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그야 벼랑 끝에 내몰린 인간은 손에 잡히는 게 무엇이든 필사적으로 매달리는 법이니까요.","JPN":"窮地に追い込まれた人間は、手に取れるものが何であっても必死にすがりつくものですから。","ENG":"That’s because people on the brink of death will do desperate things to stay alive.","TWN":"因為被逼到絕境的人，無論抓到什麼都會拼命抓住的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"헛된 소문을 믿어서라도 어머니를 살리려고 하는 당신처럼 말입니다.","JPN":"偽りの噂を信じてでも母を助けようとしているあなたのように。","ENG":"Just like how you want it to be true so you can save your mother.","TWN":"就像你為了救母親而相信那些假消息一樣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"닥쳐! 흡혈귀 주제에 사람을 이해하는 척하지 말라고!","JPN":"黙れ！　吸血鬼のくせに、人間を分かってるふりなんかするな！","ENG":"Shut up! I don’t want sympathy from a filthy vampire like you!","TWN":"閉嘴！區區吸血鬼別裝作理解人類的樣子！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"이야아아!!","JPN":"やあああっ！！","ENG":"Hrrrragh!!","TWN":"咿呀啊！！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"으앗…!","JPN":"わあっ……！","ENG":"Oof...!","TWN":"哇啊…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐하시는 거죠?","JPN":"何をしているのですか？","ENG":"What was that?","TWN":"你在做什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"고작 손으로 밀쳤다고 쓰러진 겁니까?","JPN":"手で押されただけで倒れたのですか?","ENG":"I gave a slight push and you’re already down?","TWN":"才用手推你一下就倒下了嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"우, 웃기지 마. 난…!","JPN":"ふ、ふざけるな。僕は……！","ENG":"Don’t be absurd! I...!","TWN":"開，開什麼玩笑。我…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"헉?","JPN":"はっ？","ENG":"Huh?","TWN":"啊？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이대로 방아쇠를 당기면, 당신은 죽겠죠.","JPN":"このまま引き金を引くと、あなたは死ぬでしょう。","ENG":"As soon as I pull the trigger, you’re dead.","TWN":"就這樣扣下扳機的話，你會死的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"당신에게 그런 무거운 갑옷은 어울리지 않아요. 전장에서 명예롭게 죽기엔 너무 하찮습니다.","JPN":"あなたにそのような重い鎧は似合いません。戦場で名誉ある死を迎えるなんて、あなたには価値のないこと。","ENG":"Throw away your heavy armor. It doesn’t suit you. You don’t deserve an honorable death on the battlefield.","TWN":"你不適合穿這種沉重的盔甲。在戰場上光榮地死去對你來說一點都不值。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그러니 지금부터 열을 세죠. 그전에 도망치십시오.","JPN":"ですから、今から10を数えましょう。その前に逃げてください。","ENG":"I’m going to count to ten. I suggest you run as far as you can.","TWN":"那麼從現在開始數到十，在那之前快逃跑吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"뭐… 뭐라고?","JPN":"な……何だと？","ENG":"W-what?","TWN":"你…你說什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하나… 둘…","JPN":"1……2……","ENG":"One... Two...","TWN":"一…二…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"셋… 넷…","JPN":"3……4……","ENG":"Three... Four...","TWN":"三…四…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LITTLE_SOILDER_NULL_NULL","text":{"KOREA":"크윽…!","JPN":"ううっ……！","ENG":"Errgh...!","TWN":"呃…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"다섯… 여섯…","JPN":"5……6……","ENG":"Five... Six...","TWN":"五…六…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐, 도망치지 않는다고 해도 당신에게 제 귀한 총알을 낭비하는 일은 없겠지만요.","JPN":"まあ、逃げないとしてもあなたに私の貴重な銃弾を無駄遣いすることはありませんが。","ENG":"But even if you didn’t run away, I wouldn’t have wasted my precious bullet on you anyway.","TWN":"哼，就算你不逃跑，我也不會浪費我的寶貴子彈在你身上。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…음?","JPN":"……ん？","ENG":"...Hmm?","TWN":"…嗯？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"……호오.","JPN":"……ほう。","ENG":"Ooh…","TWN":"…喔喔。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런 강력한 투기는 오랜만이로군요.","JPN":"こんな強力な闘気は久しぶりですね。","ENG":"It’s been a long time since I felt this kind of fighting spirit.","TWN":"好久沒有感受到如此強烈的鬥氣了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"살기를 전혀 숨기지 않는 걸 보니 좋은 의도로 찾아오신 건 아니겠지요?","JPN":"まったく殺気を隠していないのを見ると、友好的な意図で訪れたわけではないでしょう。","ENG":"Judging by how you’re glaring at me, I doubt you're here with good intentions.","TWN":"看你毫不掩飾殺氣，是不懷好意吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"처음 보는 늑대 아가씨.","JPN":"オオカミのお嬢さん。","ENG":"Haven’t seen you around before, wolf-girl.","TWN":"初次見面的狼人小姐。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"동족의 피비린내가 진한 걸… 네가 한 짓이야?","JPN":"同族の血の匂いがすごいな……あんたがやったのか？","ENG":"These lands reek of my people’s blood. Was this your doing?","TWN":"同族的血腥味這麼濃…是你幹的嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇습니다. 제가 이 불쌍한 짐승들에게 총탄을 선사했죠.","JPN":"そうです。私がこの可哀想な獣たちに銃弾をプレゼントしたのです。","ENG":"Yes, it is. I gave those poor beasts a bullet they deserved.","TWN":"是的，是我送這些可憐的野獸吃子彈的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그런데 당신은… 그들과 달리 공작에게 길들여진 것 같지 않군요.","JPN":"ところで、あなたは……彼らとは違って公爵に躾けられていないようですね。","ENG":"But you... You’re not like those others tamed by the Duke.","TWN":"不過…你似乎不像是被公爵馴服的野獸。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저에게 동족의 복수를 하러 온 겁니까?","JPN":"私に同族の復讐をしに来たのですか？","ENG":"Are you hear to avenge your fallen people?","TWN":"是來向我報仇的嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"엉? 그런 녀석들에겐 볼일 없어. 인간에게 굴복한 낙오자 놈일 뿐이잖아.","JPN":"あ？　そんなやつらに用はない。人間に屈服した落ちこぼれなんだろう。","ENG":"Huh? Why would I do that? I have no strays who succumbed to humans.","TWN":"嗯？我對那些傢伙沒興趣，都只是一群向人類屈服的弱雞而已。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"흐음, 그렇다면 당신도 제 심장을 노리고 온 걸까요?","JPN":"ふーん、それならあなたも私の心臓を狙ってきたのでしょうか？","ENG":"Hmm... then are you also here for my heart as well?","TWN":"嗯，那你的目標也是我的心臟嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"심장? 그 심장이 있으면 더 강해지기라도 하나?","JPN":"心臓？　その心臓があればもっと強くなれるのか？","ENG":"Your heart? Does having your heart make me stronger?","TWN":"心臟？有了那個心臟就能變得更強嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"글쎄요. 소문으로는 고위 흡혈귀의 심장을 먹으면 영생을 얻는다고 하더군요.","JPN":"どうでしょう。噂では高位の吸血鬼の心臓を食べると永生を手に入れるとか。","ENG":"I don't know, but rumors have spread that eating a high-class vampire’s heart will give eternal life.","TWN":"這個嘛，聽說吃了高階吸血鬼的心臟就能獲得永生。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"하아? 그런 하찮은 건 전혀 관심 없어.","JPN":"はあ？　そんなくだらないことに興味ない。","ENG":"Huh? I’m not interested in any of that.","TWN":"哈？那種無聊的東西我一點興趣都沒有。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"내가 원하는 건 강자와의 싸움 뿐이야.","JPN":"アタシは強者と戦いたいだけなんだ。","ENG":"All I want is to fight strong foes.","TWN":"我想要的只是與強者戰鬥。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"그런데 넌 제법 강해 보이는 걸?","JPN":"それに、あんたは結構強そうだな。","ENG":"Hey, you look pretty tough.","TWN":"看起來你挺強的嘛！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"그러니 나와 싸우자! 흡혈귀!","JPN":"だからアタシと戦え！　吸血鬼！","ENG":"So, let’s fight, vampire!","TWN":"快和我戰鬥吧！吸血鬼！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 재미있는 분이네요.","JPN":"ふふ、面白い方です。","ENG":"Hah hah, how interesting.","TWN":"呵呵，不錯不錯。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저런. 성급하셔라.","JPN":"おっと。せっかちですね。","ENG":"My, such an anxious one.","TWN":"嘖，真是太急躁了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"…내 발톱을 흘리다니. 제법이군.","JPN":"……アタシの爪を受け流すとは。やるな。","ENG":"...Impressive, you avoided my claw attack?","TWN":"…竟然能打掉我的爪子，不錯嘛。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"이건 어떠냐!","JPN":"これはどうだ！","ENG":"But, how about this!!","TWN":"這個如何！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"오호, 위험했습니다.","JPN":"ほう、危なかったですね。","ENG":"Whoa! That was a close one.","TWN":"喔吼，好險。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"강철도 찢어발기는 손톱을 가진 늑대인간이 발길질을 할 줄이야.","JPN":"鋼も切り裂く爪を持つライカンスロープが蹴りもこなすとは。","ENG":"Who would’ve thought a lycanthrope would kick instead of using its steel-shredding claws?","TWN":"擁有能撕裂鋼鐵的利爪竟然還會踢腿。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"허를 찌르는 전투 센스가 훌륭합니다.","JPN":"不意をつく戦闘センス、見事です。","ENG":"Thinking outside the box, I like it.","TWN":"你直擊要害的戰鬥品味非常出色。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아마도 그건…… 인간의 피가 섞여 있기 때문일까요?","JPN":"おそらくそれは……人間の血が混ざっているからなのでしょうか？","ENG":"Perhaps it’s because... you have human blood mixed in you?","TWN":"難道是…混有人類的血？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"뭐라고?","JPN":"何だと？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런. 회심의 기습이었습니다만, 잘 피하셨군요.","JPN":"おっと。会心の奇襲でしたが、見事によけられましたね。","ENG":"Oh my, that attack was an ace up my sleeve. Excellent footwork!","TWN":"可惡。我精心策劃的突襲，被你躲開了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"너야 말로 말라빠진 주제에 제법 쓸만한 사격 실력인걸?","JPN":"あんたこそがりがりしてるくせに、射撃の腕がなかなかだな。","ENG":"The same goes for you too. You got some shooting skills for a skinny dude.","TWN":"你這個乾瘦的傢伙，射擊技術還挺不錯的嘛！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"하지만 그 뿐이야.","JPN":"でも、それだけだ。","ENG":"But that’s all you are.","TWN":"但也就僅此而已了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"네 놈의 총구가 어디로 향하는지 보인다면, 피하는 건 간단하다고.","JPN":"貴様の銃口がどこに向かうか見えれば、避けるのは簡単なんだよ。","ENG":"If I can see where you’re aiming, dodging your bullets is easy as pie.","TWN":"只要看準你槍口的方向，就很容易躲避了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"……얼마 전 늑대인간들 사이에 새로 군림한 우두머리에 대한 소문을 들었지요.","JPN":"……この前、ライカンスロープの間で新しく頭になった者に関する噂を聞きました。","ENG":"...I’ve heard about a new alpha emerging in a lycanthrope pack.","TWN":"…前陣子聽說狼人之中出現一位新的首領。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"반쪽짜리 혈통을 가지고 강자만을 찾아 다니는 전투광이 있다고 하던데……","JPN":"不完全な血統の持ち主で、強者だけを探し回っている戦闘狂がいるらしいですが……","ENG":"That person is also half-blooded and a bloodthirsty warmonger who seeks only the strongest of foes...","TWN":"是個擁有一半狼人血統的戰鬥狂，一直在尋找強者決鬥…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그게 바로 당신이었군요.","JPN":"それがあなただったのですね。","ENG":"That description fits you like a glove.","TWN":"原來是你啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"하하, 또 이상한 소리를 하다가 기습할 생각이야?","JPN":"はは、また変なこと言って不意打ちするつもりなのか？","ENG":"Ha ha! Trying to catch me off guard, eh?","TWN":"哈哈，又在說些奇怪的話，打算偷襲嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 아뇨. 그저 조금 신기해서 말입니다.","JPN":"ふふ、いいえ。ただ少し不思議だったので。","ENG":"Hah hah, no. I’m just curious, that’s all.","TWN":"呵呵，不不。只是覺得有點神奇而已。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"반쪽짜리 혈통인 당신이 그 어떤 순혈의 늑대인간 보다 강하다는 아이러니가 말이죠.","JPN":"不完全な血統を持つあなたが純血のライカンスロープより強いというアイロニーが。","ENG":"Isn’t it ironic that a half-blood like yourself is stronger than any other pure-blood out there?","TWN":"諷刺的是，身為混種的你，卻比任何純種的狼人都要強大。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"흥, 그러고 보니 아까 그 인간 귀족이 널 결투자 프레데릭이라고 부르던데.","JPN":"ふん、そういえばさっきあの人間の貴族があんたを決闘者フレドレックと呼んでいたが。","ENG":"Hmph! Come to think of it, that human called you Frederick the Duelist.","TWN":"哼，話說剛才那個人類貴族叫你決鬥者弗雷德里克，"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"요즘 흡혈귀 놈들은 결투를 혓바닥으로 하는가 보지?","JPN":"最近の吸血鬼は舌で決闘してるのか？","ENG":"Do all vampires duel with their tongues these days?","TWN":"最近的吸血鬼都是用嘴決鬥的嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런, 제가 잠시 손님 대접에 소홀했군요.","JPN":"おっと、私としたことが、おもてなしを疎かにしてしまいましたね。","ENG":"Oh no, look where I’ve put my manners.","TWN":"哎呀，我剛剛有點怠慢了客人。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그럼 다시 춤춰 볼까요?","JPN":"それでは、また踊りましょうか？","ENG":"Well then, shall we start dancing once more?","TWN":"那我們再跳一次舞吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런…!","JPN":"しまった……！","ENG":"Gah...!","TWN":"糟糕…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"크하하! 도망만 치는 꼴이라니. 명성이 아까운걸!","JPN":"あはは！　逃げ回る様とは。あんたにはもったいない名声だ！","ENG":"Kwahaha! Quit running away and fight me already!","TWN":"哈哈哈！只會逃跑，真是辜負了你的名聲！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"피도 눈물도 없는 흡혈귀라더니, 정말 피가 흐르지 않는지 확인해 볼까!","JPN":"血も涙もない吸血鬼は、本当に血を流さないのか確認してみようじゃないか！","ENG":"Let’s see if the heartless vampire really doesn’t have a heart!","TWN":"都說你是沒血沒淚的吸血鬼，真的沒有血嗎？讓我來確認一下！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"역시 보름달 아래의 늑대인간은 강하군요.","JPN":"やはり満月のライカンスロープは強いですね。","ENG":"A lycanthrope under the full moon is just too much.","TWN":"果然月圓下的狼人很強啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 이제 밤은 끝나가고 곧 여명이 밝아 오겠지요.","JPN":"ですが、もうじき夜は明け、朝がやってくるでしょう。","ENG":"But soon, night will fall and dawn will strike.","TWN":"但是現在夜晚即將結束，黎明即將到來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"당신의 그 괴력도 얼마나 더 갈 수 있을까요?","JPN":"あなたのその怪力もあとどれほど続くのでしょうか。","ENG":"I wonder how much longer your powers will last?","TWN":"你那股怪力還能維持多久呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"하하, 우스운 걸! 마치 남의 일처럼 이야기하고 있잖아?","JPN":"はは、面白いな！　まるで人の話のように！","ENG":"Hah hah! Hilarious! You say that like the sun’s your savior!","TWN":"哈哈，真好笑！你說得好像是別人的事一樣！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"난 그저 힘이 조금 빠질 뿐이지만 흡혈귀인 넌 해가 뜨면 불타버릴 텐데?","JPN":"私はただ少し力が抜けるだけだが、吸血鬼のあんたは日が昇ると燃えるだろう？","ENG":"Yes, I won’t be as powerful as now when the sun rises. But it’ll be the death of you, vampire!","TWN":"我只是稍微有點力氣不足而已，但你是吸血鬼，太陽一出來你就會被燒成灰吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"걱정해주시는 건가요? 이 도마, 조금은 감동받았습니다.","JPN":"心配してくれるのですか？　このドマ、何気に感動しました。","ENG":"Oh, are you worried about what might happen to me? I, Doma, might be a little moved.","TWN":"你是在擔心我嗎？我都有點感動了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 괜찮아요. 저도 당신과 비슷한 처지거든요.","JPN":"ですが、大丈夫です。私もあなたと似たようなものなので。","ENG":"Nevertheless, no matter. You see, for you and I are quite alike.","TWN":"不過沒關係，我和你處境差不多。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"네 녀석? 설마?!","JPN":"貴様？　まさか！？","ENG":"Huh? You mean...!","TWN":"你這傢伙？難道？！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Ugh?!","TWN":"呃？！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"왜 내가 총탄에 맞은 거지? 분명 총구는 다른 쪽을 향하고 있었는데?","JPN":"どうしてアタシが銃に撃たれたんだ？　確かに銃口は違う方向に向けられていたはずだ。","ENG":"How did I get shot? His gun wasn’t even pointed in this direction.","TWN":"為什麼我會被子彈擊中？明明槍口是朝向另一邊的啊？！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"리볼버는 훌륭한 무기지만, 장전이 까다롭답니다.","JPN":"リボルバーは立派な武器ですが、リロード方法が厄介なのです。","ENG":"Revolvers are incredible weapons, but are quite the annoyance to reload.","TWN":"左輪手槍是很好的武器，但裝彈很麻煩。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그래서 제 코트 속엔 언제나 여분의 리볼버가 하나 더 준비되어 있지요.","JPN":"それで私のコートの中にはいつも予備のリボルバーがもう一丁用意されています。","ENG":"That’s why I always carry a spare inside my coat.","TWN":"所以我的大衣裡總是留著一把備用的左輪手槍。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아무리 당신이라도 코트 속의 총구가 어디로 향하는진 알 수 없겠죠.","JPN":"いくらあなたでも、コートの中の銃口がどこに向けられているのかはわからないでしょう。","ENG":"Even you can’t see where I’m aiming under my coat, can you?","TWN":"即使是你，也無法知道大衣裡的槍口會指向哪裡吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"큭큭, 교활한 것도 마음에 드는데.","JPN":"ククッ、小賢しいところも気に入るな。","ENG":"Keke... I even like your sly style.","TWN":"呵呵，我喜歡你的狡猾。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"그나저나 대체 무슨 총탄을 쓴 거지? 고작 한 발 맞았을 뿐인데 몸이 움직이지 않아.","JPN":"それより、いったいその銃弾は何なんだ？　1発くらっただけなのに、体が動かない。","ENG":"Anyway, what kind of bullet is it? I can’t seem to move with just one shot.","TWN":"話說回來，到底用了什麼子彈？明明只中了一槍，身體卻動不了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"프레데릭 가문에 대대로 전해지는 방식으로 제작한 마법의 은탄입니다.","JPN":"フレドレック家に代々伝わっている方法で製作した魔法の銀弾です。","ENG":"It’s a silver bullet, specially crafted by a family secret.","TWN":"這是用弗雷德里克家族代代相傳的秘方製作的魔法銀彈。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이게 효과가 있다는 건, 당신에게 괴물의 피가 흐른다는 뜻이지요.","JPN":"これが効いているということは、あなたに化け物の血が流れているということです。","ENG":"Seeing how this bullet is affecting you, it means that you have the blood of a monster running through you.","TWN":"有效果就說明你體內流著怪物的血液。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아무래도 이 결투는 제가 이긴 것 같군요.","JPN":"どうやらこの決闘は私の勝ちで終わりそうですね。","ENG":"It seems that I have won this duel.","TWN":"這場決鬥好像是我贏了吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"……그런 것 같네.","JPN":"……そうみたいだな。","ENG":"...I guess you did.","TWN":"…看來是的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"그런데 너… 태양이 떴는데도 어째서 아직 멀쩡한 거지?","JPN":"ところで、あんた……太陽が昇ってきたのにどうしてまだ平気なんだ？","ENG":"Hey... How are you not getting burned by the sun?","TWN":"你怎麼…太陽都出來了，為什麼一點事也沒有？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"설마 생긴 것만 그렇고 실은 흡혈귀가 아닌 건가?","JPN":"まさか外見だけで、実は吸血鬼じゃないのか？","ENG":"Wait, could it be that you look like a vampire but in truth you aren’t one at all?","TWN":"難道你只是長得像，但實際上並不是吸血鬼嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"외모로 사람을 평가하다니 섭섭하군요. 전 당신과 별반 다르지 않은 괴물입니다.","JPN":"見た目で人を評価するとは、悲しいことですね。私はあなたとそう変わらない化け物です。","ENG":"Shame on you for judging another being by their cover. However, I am a monster just like you.","TWN":"居然用外貌來評判人，真是讓人傷心啊。我和你沒什麼兩樣，都是怪物。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"다만, 저 역시 당신과 같은 반쪽짜리일 뿐이라서요.","JPN":"ただ、私もまたあなたと同じく不完全な存在ですので。","ENG":"Also, I am a half-blood like you too.","TWN":"也是和你一樣的混種。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"덕분에 조금 괴롭긴 하지만, 햇볕에 불타버릴 정도는 아니랍니다.","JPN":"おかげで少し辛くはありますが、日差しで燃えてしまうほどではありません。","ENG":"The sun stings a little, but not enough to burn me to death.","TWN":"雖然有點難受，但還不至於被陽光灼燒。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"흥. 시시한 진실이네.","JPN":"ふん。くだらない真実だな。","ENG":"Hmph. The truth is always a let-down, isn’t it?","TWN":"哼，無聊的真相。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"내가 졌다. 죽여.","JPN":"アタシの負けだ。殺せ。","ENG":"You win. Kill me.","TWN":"我輸了，殺了我吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"네, 그럼 사양하지 않도록 하죠.","JPN":"はい、では遠慮なく。","ENG":"Of course, with pleasure.","TWN":"好的，那我就不客氣了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…오?","JPN":"……お？","ENG":"....Hmm?","TWN":"…喔？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"유감이군요. 마침 총탄이 다 떨어졌네요.","JPN":"残念ですね。ちょうど銃弾が切れてしまいました。","ENG":"I’m sorry, but I’ve run out of bullets.","TWN":"真遺憾，子彈正好用完了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"어쩔 수 없죠. 이번엔 당신을 살려드리도록 하겠습니다.","JPN":"仕方ありません。今回に限り、あなたを見逃してあげましょう。","ENG":"Oh well. I’ll let you live this time.","TWN":"沒辦法，這次就饒你一命。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"뭐야? 지금 날 놀리는 건가?","JPN":"はあ？　アタシをばかにしてるのか？","ENG":"Huh? Are you mocking me right now?","TWN":"什麼啊？現在是在耍我嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"전혀요. 당신과 제가 한 것은 명예로운 일대일의 결투였으니까요.","JPN":"そんな。あなたと私は名誉ある一対一の決闘をしましたから。","ENG":"Not at all. You and I did an honorable duel.","TWN":"完全沒有。你我之間進行的可是一場光榮的一對一決鬥。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그리고 운은…… 결투에서 빼놓을 수 없는 중대한 요소랍니다.","JPN":"そして、運は……決闘で決して欠かせない重大な要素です。","ENG":"And one major factor of dueling is... luck.","TWN":"而運氣…也是決鬥中不可或缺的重要因素喔。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그러니, 이번엔 당신의 운이 좋았다고 해두죠.","JPN":"だから、今回はあなたが運がよかったことにしましょう。","ENG":"So, let’s just say you were lucky today.","TWN":"所以，這次就算你走運吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"무승부입니다.","JPN":"引き分けです。","ENG":"Our duel is a draw.","TWN":"平手。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YUMA_WOLF_NULL_QM","text":{"KOREA":"유스티스.","JPN":"ユースティス。","ENG":"Eustis.","TWN":"尤思蒂斯。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"그게 내 이름이다. 기억해 둬라.","JPN":"それがアタシの名前だ。覚えておけ。","ENG":"That’s my name. Don’t forget it.","TWN":"這是我的名字，記住了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"다시 대결했을 땐 널 확실하게 이겨줄 테니까.","JPN":"また対決する時には、確実に勝つからな。","ENG":"The next time we fight, I’ll make sure to defeat you.","TWN":"下次再決鬥時，我一定會徹底打敗你。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그 날을 기꺼이 기다리고 있겠습니다. 유스티스.","JPN":"その日を喜んで待っているとしましょう。ユースティス。","ENG":"I will be eagerly waiting for that day to come, Eustis.","TWN":"我非常願意等待那一天的到來，尤思蒂斯。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};